#include <stdio.h>
#include <stdlib.h>

// Structure for stack
typedef struct Stack {
    int* arr;
    int top;
    int capacity;
} Stack;

// Function to create a stack
Stack* createStack(int capacity) {
    Stack* stack = (Stack*) malloc(sizeof(Stack));
    stack->arr = (int*) malloc(sizeof(int) * capacity);
    stack->top = -1;
    stack->capacity = capacity;
    return stack;
}

// Function to check if the stack is empty
int isEmpty(Stack* stack) {
    return stack->top == -1;
}

// Function to push an element onto the stack
void push(Stack* stack, int element) {
    if (stack->top < stack->capacity - 1) {
        stack->arr[++stack->top] = element;
    }
}

// Function to pop an element from the stack
int pop(Stack* stack) {
    if (!isEmpty(stack)) {
        return stack->arr[stack->top--];
    }
    return -1; // or any other value to indicate error
}

// Function to get the top element of the stack
int top(Stack* stack) {
    if (!isEmpty(stack)) {
        return stack->arr[stack->top];
    }
    return -1; // or any other value to indicate error
}

// Function to insert an element into the stack in sorted order
void sortedInsert(Stack* stack, int element) {
    if (isEmpty(stack) || top(stack) <= element) {
        push(stack, element);
    } else {
        int temp = pop(stack);
        sortedInsert(stack, element);
        push(stack, temp);
    }
}

// Function to sort the stack in descending order
void sortStack(Stack* stack) {
    if (!isEmpty(stack)) {
        int temp = pop(stack);
        sortStack(stack);
        sortedInsert(stack, temp);
    }
}

// Function to print the stack elements
void printStack(Stack* stack) {
    for (int i = 0; i <= stack->top; i++) {
        printf("%d ", stack->arr[i]);
    }
    printf("\n");
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Stack* stack = createStack(N);
        for (int i = 0; i < N; i++) {
            int element;
            scanf("%d", &element);
            push(stack, element);
        }
        sortStack(stack);
        printStack(stack);
    }
    return 0;
}

