#include <iostream>
#include <stack>
using namespace std;

// Function to insert an element into the stack in sorted order
void sortedInsert(stack<int>& st, int element) {
    if (st.empty() || st.top() <= element) {
        st.push(element);
        return;
    }
    int temp = st.top();
    st.pop();
    sortedInsert(st, element);
    st.push(temp);
}

// Function to sort the stack in descending order
void sortStack(stack<int>& st) {
    if (st.empty())
        return;
    int temp = st.top();
    st.pop();
    sortStack(st);
    sortedInsert(st, temp);
}

// Function to print the stack elements
void printStack(stack<int>& st) {
    stack<int> temp;
    while (!st.empty()) {
        temp.push(st.top());
        st.pop();
    }
    while (!temp.empty()) {
        cout << temp.top() << " ";
        st.push(temp.top());
        temp.pop();
    }
    cout << endl;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        stack<int> st;
        for (int i = 0; i < N; i++) {
            int element;
            cin >> element;
            st.push(element);
        }
        sortStack(st);
        printStack(st);
    }
    return 0;
}

