import java.util.Stack;
import java.util.Scanner;

public class Main {
    // Function to insert an element into the stack in sorted order
    public static void sortedInsert(Stack<Integer> st, int element) {
        if (st.isEmpty() || st.peek() <= element) {
            st.push(element);
            return;
        }
        int temp = st.pop();
        sortedInsert(st, element);
        st.push(temp);
    }

    // Function to sort the stack in descending order
    public static void sortStack(Stack<Integer> st) {
        if (st.isEmpty())
            return;
        int temp = st.pop();
        sortStack(st);
        sortedInsert(st, temp);
    }

    // Function to print the stack elements
    public static void printStack(Stack<Integer> st) {
        Stack<Integer> temp = new Stack<>();
        while (!st.isEmpty()) {
            temp.push(st.pop());
        }
        while (!temp.isEmpty()) {
            System.out.print(temp.peek() + " ");
            st.push(temp.pop());
        }
        System.out.println();
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            Stack<Integer> st = new Stack<>();
            for (int i = 0; i < N; i++) {
                int element = sc.nextInt();
                st.push(element);
            }
            sortStack(st);
            printStack(st);
        }
    }
}

