function readLine() {
    return input[idx++];
}

// Function to read an integer from the input
function readInt() {
    return parseInt(readLine());
}

// Function to read a list of integers from the input
function readInts() {
    return readLine().split(' ').map(Number);
}

// Class for Stack
class Stack {
    constructor() {
        this.stack = [];
    }

    push(element) {
        this.stack.push(element);
    }

    pop() {
        if (!this.isEmpty()) {
            return this.stack.pop();
        }
        return null;
    }

    top() {
        if (!this.isEmpty()) {
            return this.stack[this.stack.length - 1];
        }
        return null;
    }

    isEmpty() {
        return this.stack.length === 0;
    }
}

// Function to insert an element into the stack in sorted order
function sortedInsert(stack, element) {
    if (stack.isEmpty() || stack.top() <= element) {
        stack.push(element);
    } else {
        let temp = stack.pop();
        sortedInsert(stack, element);
        stack.push(temp);
    }
}

// Function to sort the stack in descending order
function sortStack(stack) {
    if (stack.isEmpty())
        return;
    let temp = stack.pop();
    sortStack(stack);
    sortedInsert(stack, temp);
}

